SELECT COUNT(*) AS TOTAL FROM LATTES_P_EVENTO LP JOIN LATTES_EVENTO E ON LP.FK_EVENTO = E.PK JOIN SERVIDOR S ON LP.FK_SIAPE = S.PK_SIAPE WHERE LOWER(LP.TIPO) LIKE LOWER('%apresentacao oral%') AND E.ANO = 2023 AND LOWER(S.GENERO) = LOWER('feminino') AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%letras%') OR LOWER(S.AREA_INGRESSO_OG) LIKE LOWER('%letras%')) AND (LOWER(S.SIGLA_CAMPUS) = LOWER('uru') OR LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%uruacu%'))